import math

def euclidean_distance(p1, p2):
    return math.sqrt(sum((c1 - c2)**2 for c1, c2 in zip(p1, p2)))

def k_centers_greedy(points, k):
    if not points or k <= 0:
        return []
    if k >= len(points):
        return list(points)

    centers = []

    # Initialize the set of centers with an arbitrary point (e.g., the first point)
    centers.append(points[0]) 

    # Select k-1 more centers
    for _ in range(k - 1):
        max_min_dist = -1
        farthest_point_candidate = None

        for p in points:
            # Skip if the point is already one of the chosen centers
            if p in centers:
                continue

            min_dist_to_current_centers = float('inf')
            for center in centers:
                dist = euclidean_distance(p, center)
                min_dist_to_current_centers = min(min_dist_to_current_centers, dist)

            if min_dist_to_current_centers > max_min_dist:
                max_min_dist = min_dist_to_current_centers
                farthest_point_candidate = p

        if farthest_point_candidate is not None:
            centers.append(farthest_point_candidate)
        else:
            # No new distinct farthest point could be found,
            # indicating we might have fewer than k unique points
            # or all remaining points are very close to existing centers.
            break

    return centers
